async (page) => {
  // Warp to Mudwich
  await page.evaluate(() => {
    window.game.menu.warp.show();
    setTimeout(() => document.getElementById('warp0').click(), 500);
  });
  await page.waitForTimeout(3000);

  // Set attack style to Hack (index 0)
  await page.evaluate(() => window.game.player.setAttackStyle(0));
  await page.waitForTimeout(500);

  // Check equipment state
  const equipInfo = await page.evaluate(() => {
    const p = window.game.player;
    if (!p) return 'no player';
    // Try to get equipped weapon info
    const equipment = p.equipment;
    if (!equipment) return 'no equipment';
    try {
      const weapon = equipment.getWeapon?.() || equipment.weapon;
      return JSON.stringify({
        weapon: weapon ? {key: weapon.key || weapon.name, name: weapon.getName?.() || weapon.name} : null
      });
    } catch(e) {
      return 'error: ' + e.message;
    }
  });

  const pos = await page.evaluate(() => window.__latestGameState?.player_position);
  return JSON.stringify({pos, equipment: equipInfo});
}

async (page) => {
  // Direct canvas click to (194, 143): 1 east, 3 north from (193, 146)
  // Pixel: center(648,384) + 1*48 east, -3*48 north = (696, 240)
  await page.evaluate(({x, y}) => {
    const canvas = document.getElementById('canvas');
    canvas.dispatchEvent(new MouseEvent('mousedown', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
    canvas.dispatchEvent(new MouseEvent('mouseup', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
    canvas.dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
  }, {x: 696, y: 240});
  await page.waitForTimeout(3000);

  const pos = await page.evaluate(() => window.__latestGameState?.player_position);
  return JSON.stringify({pos});
}

