async (page) => {
  // Keep walking north in steps
  for (let targetY = 138; targetY >= 114; targetY -= 8) {
    await page.evaluate(() => window.game.player.setTarget(null));
    const pos = await page.evaluate(() => window.__latestGameState.player_position);
    if (pos.y <= 116) break;
    const r = await page.evaluate(({x, y}) => JSON.stringify(window.__clickTile(x, y)), {x: 202, y: targetY});
    await page.waitForTimeout(4000);
    const newPos = await page.evaluate(() => window.__latestGameState.player_position);
    if (newPos.y === pos.y) break; // stuck
  }
  const finalPos = await page.evaluate(() => window.__latestGameState.player_position);
  return JSON.stringify(finalPos);
}

async (page) => {
  // Continue walking north step by step
  for (let i = 0; i < 8; i++) {
    await page.evaluate(() => window.game.player.setTarget(null));
    const pos = await page.evaluate(() => window.__latestGameState.player_position);
    if (pos.y <= 116) break;
    const targetY = Math.max(pos.y - 8, 115);
    const r = await page.evaluate(({x, y}) => JSON.stringify(window.__clickTile(x, y)), {x: 202, y: targetY});
    await page.waitForTimeout(4000);
    const newPos = await page.evaluate(() => window.__latestGameState.player_position);
    if (newPos.y === pos.y) {
      // Stuck - try moving west/east slightly
      await page.evaluate(({x, y}) => JSON.stringify(window.__clickTile(x, y)), {x: 200, y: targetY});
      await page.waitForTimeout(3000);
    }
  }
  const finalPos = await page.evaluate(() => window.__latestGameState.player_position);
  return JSON.stringify(finalPos);
}

async (page) => {
  const skills = await page.evaluate(() => {
    const p = window.game && window.game.player;
    if (!p) return { error: 'no player' };
    // Check various skill storage approaches
    const result = {
      skillsObj: p.skills ? Object.keys(p.skills).slice(0, 10) : null,
      level: p.level,
      experience: p.experience
    };
    // Try to get Strength skill
    if (p.skills) {
      const skillKeys = Object.keys(p.skills);
      result.skillKeys = skillKeys;
      // Get first few skills with their data
      result.skillData = {};
      skillKeys.slice(0, 6).forEach(k => {
        const sk = p.skills[k];
        result.skillData[k] = sk && typeof sk === 'object' ? { level: sk.level, experience: sk.experience } : sk;
      });
    }
    return result;
  });
  return JSON.stringify(skills);
}
